using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented = true
};

// --- 1) Strongly-typed metadata retrieval: GetTypeInfo<T>() ---
// Returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine("=== Strongly-typed JsonTypeInfo<Person> ===");
Console.WriteLine($"Type: {personInfo.Type.Name}");
Console.WriteLine($"Kind: {personInfo.Kind}");

// Use the typed metadata to serialize
var alice = new Person("Alice", 30);
string json = JsonSerializer.Serialize(alice, personInfo);
Console.WriteLine($"Serialized: {json}");
Console.WriteLine();

// --- 2) Probe without throwing: TryGetTypeInfo ---
// Useful when the resolver might not have metadata for a given type.
Console.WriteLine("=== TryGetTypeInfo (probe without throwing) ===");

// This will succeed — the default resolver handles any type:
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Person metadata found! Kind={info!.Kind}");
}

// Now use a custom resolver that only handles Person, not Order:
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver()
};

if (limited.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("Person  → available");
else
    Console.WriteLine("Person  → NOT available");

if (limited.TryGetTypeInfo(typeof(Order), out _))
    Console.WriteLine("Order   → available");
else
    Console.WriteLine("Order   → NOT available");

// ---------- Types ----------
record Person(string Name, int Age);
record Order(int Id, decimal Total);

// A resolver that only handles Person
class LimitedResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        // Only resolve Person; return null for everything else
        if (type == typeof(Person))
            return _inner.GetTypeInfo(type, options);
        return null;
    }
}
